projectConfigSchema:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "title": "通用弹窗配置",
  "type": "object",
  "properties": {
    "mediaType": {
      "type": "string",
      "title": "素材类型",
      "description": "选择弹窗展示图片或 SVGA 动画。",
      "enum": [
        "image",
        "svga"
      ],
      "enumNames": [
        "图片",
        "SVGA动画"
      ],
      "default": "image",
      "ui:options": {
        "group": "弹窗素材"
      }
    },
    "modalImage": {
      "type": "string",
      "format": "image",
      "title": "弹窗图片",
      "description": "素材类型选择“图片”时生效。建议宽度670px，高度670-890px。",
      "default": "https://uiweb.oss-cn-chengdu.aliyuncs.com/img/通用广告弹窗/默认弹窗.png",
      "ui:options": {
        "group": "弹窗素材",
        "accept": "image/*",
        "maxSize": 5242880,
        "minWidth": 670,
        "minHeight": 670,
        "maxWidth": 670,
        "maxHeight": 890,
        "visibleWhen": {
          "field": "mediaType",
          "equals": "image"
        }
      }
    },
    "svgaSrc": {
      "type": "string",
      "title": "SVGA 文件",
      "description": "素材类型选择“SVGA动画”时生效。可上传 .svga 文件，或填写可跨域访问的 .svga 地址。",
      "default": "",
      "ui:widget": "file",
      "ui:options": {
        "group": "弹窗素材",
        "accept": ".svga,application/octet-stream",
        "maxSize": 10485760,
        "placeholder": "上传或填写 .svga 文件地址",
        "visibleWhen": {
          "field": "mediaType",
          "equals": "svga"
        }
      }
    }
  },
  "required": [
    "mediaType"
  ]
}
